//! # Encoder — DenseTensor → QuantBlock projected onto the standing subspace
//!
//! Mirrors the Lean `encode_tensor` function. For each `(i, j)` in
//! `standing × standing`, look up the dense tensor entry, quantize it
//! to `bits_per_entry` bits, and pack into the block payload.
//!
//! Phase 1 ships a uniform quantizer (same bit-width across all
//! entries). Phase 3 adds an amplitude-graded variant
//! ([`encode_tensor_graded`] / [`encode_ffn_tensor_graded`]) that
//! allocates per-row bits from the manifest's `phase_alignment`.
//!
//! ## Signed quantization (correctness fix)
//!
//! Real model weights are roughly zero-centered and ~50 % negative.
//! Earlier revisions used unsigned quantization in `[0, 2^bits)` with a
//! global `[0, 1]` assumption; that silently mapped every negative input
//! to code `0` and dropped half the signal. The current encoder uses
//! **signed** quantization with a per-block `f32` scale stored as the
//! first 4 bytes of [`QuantBlock::payload`]:
//!
//! ```text
//! payload[0..4]        : f32 LE per-block scale `s`
//! payload[4..]         : packed unsigned codes in `[0, 2^bits)` where
//!                        the signed value is `(code as i32) - 2^(bits-1)`
//!                        and the reconstructed weight is `signed × s`.
//! ```
//!
//! `s = max(|values|) / (2^(bits-1) - 1)`; `s` defaults to `1.0` when the
//! block is all zeros (so the round-trip stays defined).
//!
//! ## Graded payload layout (Phase 3, signed)
//!
//! Graded blocks are field-compatible with [`QuantBlock`]: the
//! `bits_per_entry` field stores the MAX width used. The payload prefix
//! carries the per-block scale, then the per-row width header, then the
//! per-row signed codes:
//!
//! ```text
//! payload[0..4]        : f32 LE per-block scale `s` (shared across rows)
//! payload[4..4+k]      : u8 bit-width per row, in `[1, 16]`
//! payload[4+k..]       : per-row packed signed codes; each row begins
//!                        on a byte boundary so a decoder can index rows
//!                        with `4 + k + sum(prior_row_bytes)`.
//! ```
//!
//! Graded blocks must be decoded with [`super::decoder::decode_block_graded`]
//! (or `decode_ffn_block_graded`). Uniform blocks must be decoded with
//! the existing `decode_block` / `decode_ffn_block`. The caller picks
//! the right path based on which encoder was used; the format does not
//! self-describe (per the Phase 3 contract: "keep QuantBlock field-
//! compatible, don't break Phase 1/2").

use super::format::{DenseTensor, QuantBlock, SpectralManifest};

/// Bit-width clamp shared with the decoder.
pub(super) const GRADED_MIN_BITS: u8 = 1;
pub(super) const GRADED_MAX_BITS: u8 = 16;

/// Resolve the per-row bit width for amplitude-graded encoding.
/// `width = base_bits + (extra_bits × phase_alignment[row]).round()`,
/// clamped to `[GRADED_MIN_BITS, GRADED_MAX_BITS]`.
///
/// Mirrors the spirit of Lean `recommended_quantization` from
/// `AttentionQKVDecomposition`: more bits flow to rows that the
/// calibration probe says carry more aligned (less random) signal.
#[inline]
pub(super) fn graded_row_bits(alignment: f32, base_bits: u8, extra_bits: u8) -> u8 {
    let a = if alignment.is_nan() {
        0.0
    } else {
        alignment.clamp(0.0, 1.0)
    };
    let extra = (extra_bits as f32 * a).round() as i32;
    let raw = base_bits as i32 + extra;
    raw.clamp(GRADED_MIN_BITS as i32, GRADED_MAX_BITS as i32) as u8
}

/// Length of the per-block scale prefix at the start of every payload
/// (uniform and graded). 4 bytes = `f32` LE.
pub(super) const SCALE_PREFIX_LEN: usize = 4;

/// Maximum representable signed magnitude at `bits` bits using the
/// symmetric `[-2^(bits-1), 2^(bits-1)-1]` range. Returns `0` for
/// `bits == 0` (degenerate).
#[inline]
pub(super) fn max_signed_magnitude(bits: u8) -> i32 {
    if bits == 0 {
        0
    } else if bits >= 31 {
        i32::MAX
    } else {
        (1i32 << (bits - 1)) - 1
    }
}

/// Bias added to a signed code in `[-2^(bits-1), 2^(bits-1)-1]` to map
/// it to the unsigned packing range `[0, 2^bits)`.
#[inline]
pub(super) fn signed_bias(bits: u8) -> i32 {
    if bits == 0 {
        0
    } else if bits >= 31 {
        1i32 << 30
    } else {
        1i32 << (bits - 1)
    }
}

/// Compute the per-block scale `s = max(|values|) / max_signed`.
/// Returns `1.0` when the block is all zeros (so a decoder still
/// defines a finite reconstruction even though every code rounds to 0).
pub(super) fn compute_block_scale<'a, I>(values: I, bits: u8) -> f32
where
    I: IntoIterator<Item = &'a f32>,
{
    let max_signed = max_signed_magnitude(bits);
    if max_signed <= 0 {
        return 1.0;
    }
    let mut max_abs: f32 = 0.0;
    for &v in values {
        if v.is_finite() {
            let a = v.abs();
            if a > max_abs {
                max_abs = a;
            }
        }
    }
    if max_abs <= 0.0 {
        1.0
    } else {
        max_abs / max_signed as f32
    }
}

/// Quantize a single `f32` value to a `bits`-wide signed code, returned
/// as the unsigned packing code in `[0, 2^bits)`.
///
/// Reconstruction: `((code as i32) - 2^(bits-1)) * scale ≈ x`.
/// `scale` should be the block scale from [`compute_block_scale`]; a
/// non-positive / non-finite scale falls back to `1.0`.
pub(super) fn quantize_signed(x: f32, bits: u8, scale: f32) -> u32 {
    if bits == 0 {
        return 0;
    }
    let scale = if scale.is_finite() && scale > 0.0 {
        scale
    } else {
        1.0
    };
    let max_signed = max_signed_magnitude(bits);
    let bias = signed_bias(bits);
    let min_signed = -bias;
    let xi = if x.is_nan() { 0.0 } else { (x / scale).round() };
    let signed_code = xi.clamp(min_signed as f32, max_signed as f32) as i32;
    let mask: u64 = if bits >= 31 {
        0xffff_ffffu64
    } else {
        (1u64 << bits) - 1
    };
    ((signed_code + bias) as u32) as u32 & mask as u32
}

/// Pack a sequence of n-bit codes into a contiguous byte buffer
/// (little-endian within each byte, codes packed LSB-first).
pub(super) fn pack_codes(codes: &[u32], bits: u8) -> Vec<u8> {
    if bits == 0 {
        return vec![];
    }
    let total_bits = codes.len() * bits as usize;
    let total_bytes = total_bits.div_ceil(8);
    let mut out = vec![0u8; total_bytes];
    let mut bit_pos: usize = 0;
    let mask = (1u64 << bits) - 1;
    for &code in codes {
        let value = (code as u64) & mask;
        // Splat into bytes starting at bit_pos, LSB-first.
        let byte_idx = bit_pos / 8;
        let bit_offset = bit_pos % 8;
        let lower = value << bit_offset;
        out[byte_idx] |= (lower & 0xff) as u8;
        let mut written = (8 - bit_offset).min(bits as usize);
        let mut remaining = bits as usize - written;
        let mut shifted = value >> (8 - bit_offset);
        let mut idx = byte_idx + 1;
        while remaining > 0 && idx < out.len() {
            out[idx] |= (shifted & 0xff) as u8;
            let take = remaining.min(8);
            shifted >>= 8;
            remaining = remaining.saturating_sub(take);
            written += take;
            idx += 1;
        }
        let _ = written; // silence unused-mut warning
        bit_pos += bits as usize;
    }
    out
}

/// Encode a dense tensor into a quantized block restricted to the
/// `standing × standing` submatrix defined by `manifest`. Mirrors Lean
/// `encode_tensor`.
///
/// Output dimensions: `rows = cols = manifest.k`. The payload begins
/// with a 4-byte LE `f32` per-block scale (see module docs); reconstruct
/// values as `((code as i32) - 2^(bits-1)) * scale`.
pub fn encode_tensor(
    tensor: &DenseTensor,
    manifest: &SpectralManifest,
    bits_per_entry: u8,
) -> QuantBlock {
    debug_assert!(manifest.is_well_formed());
    let k = manifest.k as usize;
    let mut values: Vec<f32> = Vec::with_capacity(k * k);
    for &row in &manifest.standing_indices {
        for &col in &manifest.standing_indices {
            values.push(tensor.get(row, col));
        }
    }
    let scale = compute_block_scale(values.iter(), bits_per_entry);
    let mut codes: Vec<u32> = Vec::with_capacity(values.len());
    for &v in &values {
        codes.push(quantize_signed(v, bits_per_entry, scale));
    }
    let mut payload =
        Vec::with_capacity(SCALE_PREFIX_LEN + (codes.len() * bits_per_entry as usize).div_ceil(8));
    payload.extend_from_slice(&scale.to_le_bytes());
    payload.extend_from_slice(&pack_codes(&codes, bits_per_entry));
    QuantBlock {
        rows: manifest.k,
        cols: manifest.k,
        bits_per_entry,
        payload,
    }
}

/// Encode a rectangular dense tensor (k × h) into a quantized block —
/// for FFN intermediate matrices where `rows = manifest.k` but
/// `cols = h` (the FFN intermediate dim). The first axis is restricted
/// to standing indices; the second is taken in full. Payload layout
/// matches [`encode_tensor`]: 4-byte `f32` scale prefix, then packed
/// signed codes.
pub fn encode_ffn_tensor(
    tensor: &DenseTensor,
    manifest: &SpectralManifest,
    intermediate_h: u32,
    bits_per_entry: u8,
) -> QuantBlock {
    debug_assert!(manifest.is_well_formed());
    let k = manifest.k as usize;
    let h = intermediate_h as usize;
    let mut values: Vec<f32> = Vec::with_capacity(k * h);
    for &row in &manifest.standing_indices {
        for col in 0..intermediate_h {
            values.push(tensor.get(row, col));
        }
    }
    let scale = compute_block_scale(values.iter(), bits_per_entry);
    let mut codes: Vec<u32> = Vec::with_capacity(values.len());
    for &v in &values {
        codes.push(quantize_signed(v, bits_per_entry, scale));
    }
    let mut payload =
        Vec::with_capacity(SCALE_PREFIX_LEN + (codes.len() * bits_per_entry as usize).div_ceil(8));
    payload.extend_from_slice(&scale.to_le_bytes());
    payload.extend_from_slice(&pack_codes(&codes, bits_per_entry));
    QuantBlock {
        rows: manifest.k,
        cols: intermediate_h,
        bits_per_entry,
        payload,
    }
}

// ──────────────────────────────────────────────────────────────────────
// PHASE 3: AMPLITUDE-GRADED QUANTIZATION
// ──────────────────────────────────────────────────────────────────────

/// Quantization strategy mirroring Lean `QuantizationStrategy` from
/// `AttentionQKVDecomposition`. Each entry is `(base_bits, extra_bits)`
/// where `extra_bits` is the maximum additional width awarded to the
/// highest-aligned rows.
///
/// Aggressive on Q/K (low base + high extra → most rows quantize tight,
/// only the most aligned rows widen). Conservative on V (higher base +
/// low extra → V floor stays high so gated information survives).
#[derive(Debug, Clone, Copy)]
pub struct GradedQkvBudget {
    pub q: (u8, u8),
    pub k: (u8, u8),
    pub v: (u8, u8),
}

impl GradedQkvBudget {
    /// Default mirroring Lean `recommended_quantization`. Q/K get a
    /// tight 4-bit floor with up to +4 bits for the most aligned rows
    /// (clamped to 8). V gets an 8-bit floor with at most +2 extra
    /// (clamped to 10) so the gated value path keeps headroom.
    pub fn recommended() -> Self {
        Self {
            q: (4, 4),
            k: (4, 4),
            v: (8, 2),
        }
    }
}

/// Length of the per-row width header at the start of a graded payload.
/// One byte per standing row.
#[inline]
pub(super) fn graded_header_len(rows: u32) -> usize {
    rows as usize
}

/// Per-row scale derived from the block-level `scale` (sized against
/// the narrowest row's signed range). Rows wider than `min_width` get
/// a proportionally smaller step so they keep the same dynamic range
/// but with finer precision. Both encoder and decoder use this same
/// derivation so the format only needs to ship one scale.
#[inline]
pub(super) fn row_scale_for_width(block_scale: f32, min_width: u8, row_width: u8) -> f32 {
    if row_width <= min_width || min_width == 0 {
        return block_scale;
    }
    let extra = (row_width - min_width) as u32;
    if extra >= 31 {
        return block_scale; // pathological; avoid f32 underflow blowup
    }
    block_scale / ((1u32 << extra) as f32)
}

/// Pack a graded payload: 4-byte `f32` LE scale prefix, then per-row
/// bit-width header, then per-row packed codes. Each row's codes start
/// on a byte boundary so a decoder can index rows with
/// `SCALE_PREFIX_LEN + header_len + sum(prior_row_bytes)`.
fn pack_graded_payload(
    scale: f32,
    row_widths: &[u8],
    row_codes: &[Vec<u32>],
    cols: u32,
) -> Vec<u8> {
    debug_assert_eq!(row_widths.len(), row_codes.len());
    let header_len = row_widths.len();
    // Pre-size: scale + header + sum of row byte lengths.
    let mut total = SCALE_PREFIX_LEN + header_len;
    for &w in row_widths {
        let bits = cols as usize * w as usize;
        total += bits.div_ceil(8);
    }
    let mut out = Vec::with_capacity(total);
    out.extend_from_slice(&scale.to_le_bytes());
    out.extend_from_slice(row_widths);
    for (codes, &w) in row_codes.iter().zip(row_widths.iter()) {
        let row_bytes = pack_codes(codes, w);
        out.extend_from_slice(&row_bytes);
    }
    out
}

/// Encode a tensor with per-row amplitude-graded bit widths.
///
/// `width(row) = clamp(base_bits + round(extra_bits × phase_alignment[row]),
/// GRADED_MIN_BITS, GRADED_MAX_BITS)`.
///
/// Mirrors Lean `recommended_quantization` from
/// `AttentionQKVDecomposition`: aggressive on Q/K (low base + high
/// extra), conservative on V (higher base + low extra).
///
/// The output [`QuantBlock`] is field-compatible with the uniform
/// encoder. `bits_per_entry` carries the MAX width seen so the decoder
/// can size its scratch buffer; the payload begins with a `[u8; k]`
/// per-row table (see module docs for layout). Decode with
/// [`super::decoder::decode_block_graded`].
///
/// When `extra_bits == 0` and all phase alignments collapse to a
/// constant, every row's width equals `base_bits` and the result is
/// equivalent (modulo the per-row header) to the uniform encoder.
pub fn encode_tensor_graded(
    tensor: &DenseTensor,
    manifest: &SpectralManifest,
    base_bits: u8,
    extra_bits: u8,
) -> QuantBlock {
    debug_assert!(manifest.is_well_formed());
    let k = manifest.k as usize;
    // First pass: gather every standing-block value plus the per-row
    // bit widths. A single per-block scale is mandated by the format
    // (4-byte prefix); to keep narrow rows from saturating it is sized
    // against the MIN width across all rows so the tightest dynamic
    // range still covers `max_abs`. Wider rows then get finer step
    // (`scale / 2^(width - min_width)`) within the same range.
    let mut row_widths: Vec<u8> = Vec::with_capacity(k);
    let mut row_values: Vec<Vec<f32>> = Vec::with_capacity(k);
    let mut max_width: u8 = GRADED_MIN_BITS;
    let mut min_width: u8 = GRADED_MAX_BITS;
    for (local_row, &row) in manifest.standing_indices.iter().enumerate() {
        let alignment = manifest
            .phase_alignment
            .get(local_row)
            .copied()
            .unwrap_or(0.0);
        let width = graded_row_bits(alignment, base_bits, extra_bits);
        max_width = max_width.max(width);
        min_width = min_width.min(width);
        let mut values: Vec<f32> = Vec::with_capacity(k);
        for &col in &manifest.standing_indices {
            values.push(tensor.get(row, col));
        }
        row_widths.push(width);
        row_values.push(values);
    }
    let scale = compute_block_scale(row_values.iter().flat_map(|r| r.iter()), min_width);
    let mut row_codes: Vec<Vec<u32>> = Vec::with_capacity(k);
    for (values, &width) in row_values.iter().zip(row_widths.iter()) {
        let row_scale = row_scale_for_width(scale, min_width, width);
        let mut codes: Vec<u32> = Vec::with_capacity(values.len());
        for &v in values {
            codes.push(quantize_signed(v, width, row_scale));
        }
        row_codes.push(codes);
    }
    let payload = pack_graded_payload(scale, &row_widths, &row_codes, manifest.k);
    QuantBlock {
        rows: manifest.k,
        cols: manifest.k,
        bits_per_entry: max_width,
        payload,
    }
}

/// Encode a rectangular FFN tensor with per-row graded bit widths.
/// First axis is restricted to standing indices (one width per row);
/// second axis is taken in full (each row packs `intermediate_h` codes
/// at its own width). See [`encode_tensor_graded`] for layout details.
pub fn encode_ffn_tensor_graded(
    tensor: &DenseTensor,
    manifest: &SpectralManifest,
    intermediate_h: u32,
    base_bits: u8,
    extra_bits: u8,
) -> QuantBlock {
    debug_assert!(manifest.is_well_formed());
    let k = manifest.k as usize;
    let h = intermediate_h as usize;
    let mut row_widths: Vec<u8> = Vec::with_capacity(k);
    let mut row_values: Vec<Vec<f32>> = Vec::with_capacity(k);
    let mut max_width: u8 = GRADED_MIN_BITS;
    let mut min_width: u8 = GRADED_MAX_BITS;
    for (local_row, &row) in manifest.standing_indices.iter().enumerate() {
        let alignment = manifest
            .phase_alignment
            .get(local_row)
            .copied()
            .unwrap_or(0.0);
        let width = graded_row_bits(alignment, base_bits, extra_bits);
        max_width = max_width.max(width);
        min_width = min_width.min(width);
        let mut values: Vec<f32> = Vec::with_capacity(h);
        for col in 0..intermediate_h {
            values.push(tensor.get(row, col));
        }
        row_widths.push(width);
        row_values.push(values);
    }
    let scale = compute_block_scale(row_values.iter().flat_map(|r| r.iter()), min_width);
    let mut row_codes: Vec<Vec<u32>> = Vec::with_capacity(k);
    for (values, &width) in row_values.iter().zip(row_widths.iter()) {
        let row_scale = row_scale_for_width(scale, min_width, width);
        let mut codes: Vec<u32> = Vec::with_capacity(values.len());
        for &v in values {
            codes.push(quantize_signed(v, width, row_scale));
        }
        row_codes.push(codes);
    }
    let payload = pack_graded_payload(scale, &row_widths, &row_codes, intermediate_h);
    QuantBlock {
        rows: manifest.k,
        cols: intermediate_h,
        bits_per_entry: max_width,
        payload,
    }
}

#[cfg(test)]
mod tests {
    use super::super::manifest::stub_first_k_manifest;
    use super::*;

    fn dense(rows: u32, cols: u32, fill: f32) -> DenseTensor {
        DenseTensor {
            rows,
            cols,
            data: vec![fill; (rows * cols) as usize],
        }
    }

    #[test]
    fn quantize_zero_codes_to_bias() {
        // Signed zero with any positive scale maps to the bias code
        // (the unsigned representation of signed 0).
        assert_eq!(quantize_signed(0.0, 4, 1.0), signed_bias(4) as u32);
        assert_eq!(quantize_signed(0.0, 8, 0.5), signed_bias(8) as u32);
        // NaN treated as zero.
        assert_eq!(quantize_signed(f32::NAN, 4, 1.0), signed_bias(4) as u32);
    }

    #[test]
    fn quantize_signed_saturates_symmetrically() {
        // 4-bit signed: range [-8, 7]. Bias = 8. So +max value → code
        // 7 + 8 = 15; -max value → code -8 + 8 = 0.
        let s = 0.1_f32;
        let big_pos = quantize_signed(7.0 * s, 4, s);
        let big_neg = quantize_signed(-8.0 * s, 4, s);
        assert_eq!(big_pos, 15);
        assert_eq!(big_neg, 0);
        // Saturation past the range stays clamped.
        assert_eq!(quantize_signed(99.0 * s, 4, s), 15);
        assert_eq!(quantize_signed(-99.0 * s, 4, s), 0);
    }

    #[test]
    fn compute_block_scale_zero_block_is_one() {
        let zeros: Vec<f32> = vec![0.0; 16];
        let s = compute_block_scale(zeros.iter(), 8);
        assert_eq!(s, 1.0, "all-zero block must default scale to 1.0");
    }

    #[test]
    fn compute_block_scale_uses_max_signed() {
        // 8-bit signed: max_signed = 127. max_abs = 1.0 → scale = 1/127.
        let vals = vec![-1.0, 0.0, 0.5, 1.0];
        let s = compute_block_scale(vals.iter(), 8);
        let expected = 1.0_f32 / 127.0_f32;
        assert!((s - expected).abs() < 1e-7, "scale {} vs {}", s, expected);
    }

    #[test]
    fn pack_codes_round_trip_4bit() {
        // Two 4-bit codes pack into one byte.
        let codes = vec![0b1010, 0b0101];
        let bytes = pack_codes(&codes, 4);
        assert_eq!(bytes.len(), 1);
        assert_eq!(bytes[0], 0b0101_1010);
    }

    #[test]
    fn pack_codes_byte_count_is_ceiling() {
        // 5 codes × 4 bits = 20 bits = 3 bytes (ceiling).
        let codes = vec![1, 2, 3, 4, 5];
        let bytes = pack_codes(&codes, 4);
        assert_eq!(bytes.len(), 3);
    }

    #[test]
    fn encode_tensor_dimensions() {
        let t = dense(100, 100, 0.5);
        let m = stub_first_k_manifest(100, 0.30);
        let block = encode_tensor(&t, &m, 4);
        assert_eq!(block.rows, m.k);
        assert_eq!(block.cols, m.k);
        assert_eq!(block.bits_per_entry, 4);
        // SCALE_PREFIX_LEN + 30 × 30 × 4 bits = 4 + 450 = 454 bytes.
        assert_eq!(block.payload.len(), SCALE_PREFIX_LEN + 450);
    }

    #[test]
    fn encode_ffn_dimensions() {
        let t = dense(100, 256, 0.5);
        let m = stub_first_k_manifest(100, 0.30);
        let block = encode_ffn_tensor(&t, &m, 256, 8);
        assert_eq!(block.rows, m.k);
        assert_eq!(block.cols, 256);
        // SCALE_PREFIX_LEN + 30 × 256 × 8 bits = 4 + 7680 bytes.
        assert_eq!(block.payload.len(), SCALE_PREFIX_LEN + 7680);
    }

    // ──────────────────────────────────────────────────────────────────
    // Phase 3: amplitude-graded encoder
    // ──────────────────────────────────────────────────────────────────

    fn graded_manifest(d: u32, k: u32, alignments: &[f32]) -> SpectralManifest {
        assert_eq!(alignments.len(), k as usize);
        SpectralManifest {
            d,
            k,
            standing_indices: (0..k).collect(),
            amplitudes: vec![0.5; k as usize],
            phase_alignment: alignments.to_vec(),
        }
    }

    #[test]
    fn graded_row_bits_clamps_and_rounds() {
        // alignment 1.0 → base + extra; 0.0 → base; halfway rounds up.
        assert_eq!(graded_row_bits(1.0, 4, 4), 8);
        assert_eq!(graded_row_bits(0.0, 4, 4), 4);
        assert_eq!(graded_row_bits(0.5, 4, 4), 6);
        // Clamps to GRADED_MAX_BITS at the top.
        assert_eq!(graded_row_bits(1.0, 14, 8), GRADED_MAX_BITS);
        // Clamps to GRADED_MIN_BITS at the bottom (degenerate base=0).
        assert_eq!(graded_row_bits(0.0, 0, 0), GRADED_MIN_BITS);
        // NaN alignment treated as 0.
        assert_eq!(graded_row_bits(f32::NAN, 5, 3), 5);
    }

    #[test]
    fn graded_falls_back_to_uniform_when_extra_bits_zero() {
        // With extra_bits=0, every row uses base_bits regardless of
        // phase alignment. Both encoders share the per-block scale
        // prefix; the graded payload also has a k-byte width header.
        // Beyond those metadata bytes, the packed codes are bit-for-bit
        // identical.
        let t = dense(64, 64, 0.5);
        let m = stub_first_k_manifest(64, 0.25); // k = 16
        let bits: u8 = 4;
        let uniform = encode_tensor(&t, &m, bits);
        let graded = encode_tensor_graded(&t, &m, bits, 0);

        assert_eq!(graded.rows, uniform.rows);
        assert_eq!(graded.cols, uniform.cols);
        assert_eq!(graded.bits_per_entry, bits);

        let header_len = graded_header_len(m.k);
        assert!(graded.payload.len() >= SCALE_PREFIX_LEN + header_len);
        // Per-block scale prefix matches between uniform and graded
        // (same input, same effective max-width).
        assert_eq!(
            &graded.payload[..SCALE_PREFIX_LEN],
            &uniform.payload[..SCALE_PREFIX_LEN],
            "scale prefix should match"
        );
        // Header: every row is `bits` wide.
        for &w in &graded.payload[SCALE_PREFIX_LEN..SCALE_PREFIX_LEN + header_len] {
            assert_eq!(w, bits, "graded header should be uniform when extra_bits=0");
        }
        // Code body matches the uniform encoder byte-for-byte. Each row
        // is byte-aligned: 16 cols × 4 bits = 8 bytes per row, 16 rows
        // → 128 code bytes.
        let graded_codes = &graded.payload[SCALE_PREFIX_LEN + header_len..];
        let uniform_codes = &uniform.payload[SCALE_PREFIX_LEN..];
        assert_eq!(graded_codes.len(), uniform_codes.len());
        assert_eq!(graded_codes, uniform_codes);
    }

    #[test]
    fn graded_uses_more_bits_for_high_alignment() {
        // Two rows with alignments [0.0, 1.0]. base=4, extra=4 → widths
        // [4, 8]. Header reflects this; max-width field equals 8.
        let d: u32 = 4;
        let k: u32 = 2;
        let alignments = [0.0_f32, 1.0_f32];
        let m = graded_manifest(d, k, &alignments);
        let mut data = vec![0.5_f32; (d * d) as usize];
        // Make the values non-trivial so the row sizes differ as expected.
        for v in &mut data {
            *v = 0.25;
        }
        let t = DenseTensor {
            rows: d,
            cols: d,
            data,
        };

        let block = encode_tensor_graded(&t, &m, 4, 4);
        assert_eq!(
            block.bits_per_entry, 8,
            "max width should match the high-alignment row"
        );
        let header_len = graded_header_len(m.k);
        assert_eq!(
            block.payload[SCALE_PREFIX_LEN + 0],
            4,
            "low-alignment row uses base bits"
        );
        assert_eq!(
            block.payload[SCALE_PREFIX_LEN + 1],
            8,
            "high-alignment row uses base + extra"
        );

        // Row 0: 2 cols × 4 bits = 8 bits = 1 byte. Row 1: 2 × 8 = 2 bytes.
        let expected_len = SCALE_PREFIX_LEN + header_len + 1 + 2;
        assert_eq!(block.payload.len(), expected_len);
    }

    #[test]
    fn graded_ffn_widths_match_alignment_vector() {
        // FFN variant: same width derivation, different cols axis.
        let d: u32 = 3;
        let k: u32 = 3;
        let h: u32 = 5;
        let alignments = [0.0_f32, 0.5_f32, 1.0_f32];
        let m = graded_manifest(d, k, &alignments);
        let t = DenseTensor {
            rows: d,
            cols: h,
            data: vec![0.5; (d * h) as usize],
        };
        let block = encode_ffn_tensor_graded(&t, &m, h, 4, 4);
        let header_len = graded_header_len(m.k);
        assert_eq!(block.payload[SCALE_PREFIX_LEN + 0], 4);
        assert_eq!(block.payload[SCALE_PREFIX_LEN + 1], 6); // 4 + round(4 × 0.5)
        assert_eq!(block.payload[SCALE_PREFIX_LEN + 2], 8);
        assert_eq!(block.bits_per_entry, 8);
        assert_eq!(block.cols, h);
        // Row byte sizes: ceil(5×4/8)=3, ceil(5×6/8)=4, ceil(5×8/8)=5 → 12.
        assert_eq!(
            block.payload.len(),
            SCALE_PREFIX_LEN + header_len + 3 + 4 + 5
        );
    }

    #[test]
    fn recommended_budget_matches_lean_strategy() {
        // Lean intent: aggressive Q/K, conservative V.
        let b = GradedQkvBudget::recommended();
        assert!(
            b.q.0 <= b.v.0,
            "Q base should be <= V base (aggressive vs conservative)"
        );
        assert!(b.k.0 <= b.v.0, "K base should be <= V base");
        assert!(
            b.q.1 >= b.v.1,
            "Q extra should be >= V extra (more headroom on tight base)"
        );
        assert!(b.k.1 >= b.v.1);
    }
}
